						document.body.addEventListener( "click", function( event ) {
							if( event.target.matches( ".notice.stackable_notice_gutenberg_plugin button.notice-dismiss" ) ) {
								wp.ajax.post( "stackable_notice_gutenberg_plugin_ignore" );
							}
						} );
					} )();
					</script>' )

array_filter(
				$blocksy_static_files,
				function( $file ) {
					return isset( $file['id'] ) && in_array( $file['id'], array( 'ct-main-styles', 'ct-stackable-styles' ), true );
				}
			)

array_map(function($val, $i) {
				if ($i === 3) {
					$opacity = floatval($val);
					return str_pad(dechex(ceil($opacity * 255)), 2, '0', STR_PAD_LEFT);
				}
				$hex = dechex(intval($val));
				return str_pad($hex, 2, '0', STR_PAD_LEFT);
			}, $rgba, array_keys($rgba))

